/* ── Journal Entry Form ────────────────────────────────────────
 * Modal form for creating or editing a journal entry.
 * Used by the DmJournal page.
 * ─────────────────────────────────────────────────────────────── */

import { useState } from "react";
import { Button } from "@/components/ui/Button";
import type { JournalEntry } from "@/types";

function uid(prefix: string): string {
  return `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

interface JournalEntryFormProps {
  initialData?: JournalEntry;
  onSubmit: (entry: JournalEntry) => void;
  onCancel: () => void;
}

const ENTRY_TYPES: JournalEntry["type"][] = ["session", "note", "lore", "quest"];

export function JournalEntryForm({ initialData, onSubmit, onCancel }: JournalEntryFormProps) {
  const [title, setTitle] = useState(initialData?.title ?? "");
  const [content, setContent] = useState(initialData?.content ?? "");
  const [type, setType] = useState<JournalEntry["type"]>(initialData?.type ?? "note");
  const [sessionNumber, setSessionNumber] = useState<number | undefined>(initialData?.sessionNumber);
  const [tagInput, setTagInput] = useState("");
  const [tags, setTags] = useState<string[]>(initialData?.tags ?? []);

  const addTag = () => {
    const tag = tagInput.trim().toLowerCase().replace(/\s+/g, "-");
    if (tag && !tags.includes(tag)) {
      setTags((prev) => [...prev, tag]);
    }
    setTagInput("");
  };

  const removeTag = (tag: string) => {
    setTags((prev) => prev.filter((t) => t !== tag));
  };

  const handleSubmit = () => {
    if (!title.trim()) return;

    const entry: JournalEntry = {
      id: initialData?.id ?? uid("jrn"),
      title: title.trim(),
      content: content.trim(),
      tags,
      type,
      sessionNumber: type === "session" ? sessionNumber : undefined,
      createdAt: initialData?.createdAt ?? Date.now(),
      updatedAt: Date.now(),
    };

    onSubmit(entry);
  };

  return (
    <div className="space-y-5">
      <div>
        <label className="mb-1 block text-xs font-medium text-surface-400">Title</label>
        <input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="e.g. Session 3: The Dungeon Descent"
          className="w-full rounded-lg border border-surface-700 bg-surface-800 px-3 py-2 text-sm text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none" />
      </div>

      <div className="grid grid-cols-2 gap-3">
        <div>
          <label className="mb-1 block text-xs font-medium text-surface-400">Type</label>
          <div className="flex gap-1.5">
            {ENTRY_TYPES.map((t) => (
              <button key={t} onClick={() => setType(t)}
                className={`flex-1 rounded-lg px-3 py-2 text-xs font-medium capitalize transition-colors ${
                  type === t
                    ? "bg-accent-500/15 text-accent-400 border border-accent-500/30"
                    : "bg-surface-800 text-surface-400 border border-surface-700 hover:border-surface-600"
                }`}>
                {t === "session" ? "🎲" : t === "note" ? "📝" : t === "lore" ? "📜" : "⚔"} {t}
              </button>
            ))}
          </div>
        </div>
        {type === "session" && (
          <div>
            <label className="mb-1 block text-xs font-medium text-surface-400">Session #</label>
            <input type="number" min={1} value={sessionNumber ?? ""} onChange={(e) => setSessionNumber(parseInt(e.target.value) || undefined)}
              className="w-full rounded-lg border border-surface-700 bg-surface-800 px-3 py-2 text-sm text-surface-100 focus:border-accent-500 focus:outline-none" />
          </div>
        )}
      </div>

      <div>
        <label className="mb-1 block text-xs font-medium text-surface-400">Content</label>
        <textarea value={content} onChange={(e) => setContent(e.target.value)} rows={8}
          placeholder="Write your journal entry here... Use markdown-like formatting for structure."
          className="w-full rounded-lg border border-surface-700 bg-surface-800 px-3 py-2 text-sm text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none resize-y" />
      </div>

      <div>
