{"content": "/* ── Campaign Notes Encryption Toggle ──────────────────────────
 * A simple visual obfuscation toggle for DM notes.
 * When locked, text is replaced with dots (useful for screen-sharing).
 * ─────────────────────────────────────────────────────────────── */

import { useState, type ReactNode } from "react";
import { Button } from "@/components/ui/Button";

interface LockableNotesProps {
  children: ReactNode;
  /** Initial lock state */
  defaultLocked?: boolean;
}

export function LockableNotes({ children, defaultLocked = false }: LockableNotesProps) {
  const [locked, setLocked] = useState(defaultLocked);

  const textContent = typeof children === "string" ? children : "";

  return (
    <div className="relative">
      <div className="absolute -top-2 right-2 z-10">
        <Button
          size="xs"
          variant="ghost"
          onClick={() => setLocked(o => !o)}
          className={locked ? "text-divine-400" : "text-surface-500"}
          aria-label={locked ? "Unlock notes" : "Lock notes"}
        >
          {locked ? "🔒" : "🔓"}
        </Button>
      </div>
      <div className={`rounded-lg bg-surface-800 p-4 ${locked ? "select-none" : ""}`}>
        {locked ? (
          <p className="text-sm text-surface-500 font-mono tracking-widest">
            {textContent ? textContent.split("").map(() => "•").join("") : "••••••••"}
          </p>
        ) : (
          children
        )}
      </div>
      {locked && (
        <p className="mt-1 text-[10px] text-surface-600 text-center italic">
          Notes are locked — click 🔒 to reveal
        </p>
      )}
    </div>
  );
}
